class Solution:
    def alternatingSubarray(self, nums: List[int]) -> int:
        max_len = -1
        n = len(nums)

        for i in range(n - 1):
            if nums[i + 1] == nums[i] + 1:
                length = 2
                j = i + 2
                while j < n and nums[j] == nums[j - 2]:
                    length += 1
                    j += 1
                max_len = max(max_len, length)

        return max_len if max_len > 1 else -1
